-        return fullExpression == null ? set.ToList() : set.Where(fullExpression).ToList();
+
+        var query = db.Set<M>().AsNoTracking().AsQueryable();
+        if (fullExpression != null)
+        {
+            query = query.Where(fullExpression);
+        }
+
+        var skip = rpt?.query?.skip ?? 0;
+        if (skip > 0)
